-- Create "chat_session_summaries" table
CREATE TABLE "chat_session_summaries" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "version" bigint NOT NULL,
  "schema_version" character varying NOT NULL,
  "source_first_sequence" bigint NOT NULL,
  "source_last_sequence" bigint NOT NULL,
  "source_turn_count" bigint NOT NULL,
  "source_digest" character varying NOT NULL,
  "content" jsonb NOT NULL,
  "generated_at" timestamptz NOT NULL,
  "created_at" timestamptz NOT NULL,
  "chat_session_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "chat_session_summaries_chat_sessions_summaries" FOREIGN KEY ("chat_session_id") REFERENCES "chat_sessions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "chatsessionsummary_chat_session_id_generated_at" to table: "chat_session_summaries"
CREATE INDEX "chatsessionsummary_chat_session_id_generated_at" ON "chat_session_summaries" ("chat_session_id", "generated_at");
-- Create index "chatsessionsummary_chat_session_id_source_digest" to table: "chat_session_summaries"
CREATE UNIQUE INDEX "chatsessionsummary_chat_session_id_source_digest" ON "chat_session_summaries" ("chat_session_id", "source_digest");
-- Create index "chatsessionsummary_chat_session_id_version" to table: "chat_session_summaries"
CREATE UNIQUE INDEX "chatsessionsummary_chat_session_id_version" ON "chat_session_summaries" ("chat_session_id", "version");
